oxy_webhelp_navlinks = {"tocId-d26997e26217":{"topics":[{"title":"IBM Db2","shortdesc":"<p class=\"shortdesc\">With IBM Db2 workloads, you can automate complex tasks such as database discovery and         data protection for managing databases.<\/p>","href":"db2\/ibm_db2.html","attributes":{"data-id":"ibm_db2"},"menu":{"hasChildren":false},"tocID":"ibm_db2-d26997e26218","next":"ibm_db2-d26997e26218"},{"title":"IBM Informix","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides native data protection and recovery for IBM Informix         instances.<\/p>","href":"informix\/ibm_informix.html","attributes":{"data-id":"ibm_informix"},"menu":{"hasChildren":false},"tocID":"ibm_informix-d26997e27103","next":"ibm_informix-d26997e27103"},{"title":"Microsoft SQL Server databases","shortdesc":"<p class=\"shortdesc\">A Rubrik cluster provides data management and protection for Microsoft SQL Server         databases.<\/p>","href":"common\/sql_server_databases.html","attributes":{"data-id":"sql_server_databases"},"menu":{"hasChildren":false},"tocID":"sql_server_databases-d26997e27405","next":"sql_server_databases-d26997e27405"},{"title":"MongoDB workloads","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> protects your MongoDB sources, databases, and collections,         ensuring optimal storage efficiency and smooth database operations with its advanced         security features and strong data protection.<\/p>","href":"mongodb\/mongodb_workloads.html","attributes":{"data-id":"mongodb_workloads"},"menu":{"hasChildren":false},"tocID":"mongodb_workloads-d26997e28104","next":"mongodb_workloads-d26997e28104"},{"title":"MySQL","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects the MySQL databases from accidental deletions,         ransomware attacks, and other potential threats.<\/p>","href":"mysql\/mysql.html","attributes":{"data-id":"mysql"},"menu":{"hasChildren":false},"tocID":"mysql-d26997e28645","next":"mysql-d26997e28645"},{"title":"Oracle databases","shortdesc":"<p class=\"shortdesc\">You can use <span class=\"ph\">RSC<\/span> to back up, archive, replicate, and recover Oracle         databases.<\/p>","href":"oracle\/oracle_databases_rsc.html","attributes":{"data-id":"oracle_databases_rsc"},"menu":{"hasChildren":false},"tocID":"oracle_databases_rsc-d26997e29238","next":"oracle_databases_rsc-d26997e29238"},{"title":"PostgreSQL","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> protects your PostgreSQL cluster by simplifying complex         backup and recovery processes, discovering the databases automatically, and protecting data         using SLA Domains.<\/p>","href":"postgresql\/postgresql.html","attributes":{"data-id":"postgresql"},"menu":{"hasChildren":false},"tocID":"postgresql-d26997e30694","next":"postgresql-d26997e30694"},{"title":"SAP HANA databases","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> enables administrators to implement backup policies on SAP HANA         databases running on public clouds and on-premises.<\/p>","href":"saas\/sap_hana_protection.html","attributes":{"data-id":"sap_hana_protection"},"menu":{"hasChildren":false},"tocID":"sap_hana_protection-d26997e30961","next":"sap_hana_protection-d26997e30961"}]}};